import javax.naming.Context;
import javax.naming.NamingEnumeration;
import javax.naming.directory.Attribute;
import javax.naming.directory.Attributes;
import javax.naming.directory.DirContext;
import javax.naming.directory.InitialDirContext;
import java.util.HashMap;
import java.util.Map;

public class LDAPUserSearch {

    private static final String LDAP_URL = "ldap://your_ldap_server_url";
    private static final String LDAP_USER = "your_ldap_username";
    private static final String LDAP_PASSWORD = "your_ldap_password";

    public static Map<String, String> searchUserByUsername(String username) throws Exception {
        Map<String, String> userAttributes = new HashMap<>();

        Context ctx = new InitialDirContext(getContext());
        String ldapQuery = "(&(objectClass=user)(uid=" + username + "))";
        NamingEnumeration<?> results = ctx.search(LDAP_URL, ldapQuery, null);

        while (results.hasMoreElements()) {
            Attributes attrs = ((Attributes) results.next()).getAttributes();
            userAttributes.put("email", (String) attrs.get("mail").get());
            userAttributes.put("fullName", (String) attrs.get("cn").get());
            userAttributes.put("department", (String) attrs.get("department").get());
        }

        ctx.close();
        return userAttributes;
    }

    private static Context getContext() throws Exception {
        Hashtable<String, String> env = new Hashtable<>();
        env.put(Context.INITIAL_CONTEXT_FACTORY, "com.sun.jndi.ldap.LdapCtxFactory");
        env.put(Context.PROVIDER_URL, LDAP_URL);
        env.put(Context.SECURITY_PRINCIPAL, LDAP_USER);
        env.put(Context.SECURITY_CREDENTIALS, LDAP_PASSWORD);
        env.put(Context.SECURITY_AUTHENTICATION, "simple");
        return new InitialDirContext(env);
    }
}